[['appointments'], ['id', 'patient_id', 'doctor_id', 'appointment_date', 'appointment_time', 'status'], '<?php\n\n// Migration: Create appointments table\n\n$sql = "\nCREATE TABLE IF NOT EXISTS appointments (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    patient_id INT NOT NULL,\n    doctor_id INT NOT NULL,\n    appointment_date DATE NOT NULL,\n    appointment_time TIME NOT NULL,\n    status ENUM(\'pending\', \'confirmed\', \'cancelled\', \'completed\') DEFAULT \'pending\',\n    reason TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    FOREIGN KEY (patient_id) REFERENCES patients(id) ON DELETE CASCADE,\n    FOREIGN KEY (doctor_id) REFERENCES doctors(id) ON DELETE CASCADE\n);\n";\n\n// Execute the SQL statement\n// This would typically be executed through a database connection\n// For example: $pdo->exec($sql);\n\necho "Appointments table created successfully";\n?>']